#include <bits/stdc++.h>
using namespace std;

long long cntSum(long long s, long long N){
    if(s <= N+1) return s-1;
    return 2*N - s + 1;
}

long long cntDiff(long long d, long long N){
    return N - llabs(d);
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        long long N; int K; cin>>N>>K;
        unordered_set<long long> sumSet; sumSet.reserve(K*2);
        unordered_set<long long> diffSet; diffSet.reserve(K*2);
        for(int i=0;i<K;++i){
            long long x,y;cin>>x>>y;
            sumSet.insert(x+y);
            diffSet.insert(x-y);
        }
        vector<long long> sums(sumSet.begin(), sumSet.end());
        vector<long long> diffs(diffSet.begin(), diffSet.end());
        // sort diffs by parity
        vector<long long> evenDiffs, oddDiffs;
        evenDiffs.reserve(diffs.size()); oddDiffs.reserve(diffs.size());
        for(long long d: diffs){
            if((d&1LL)==0) evenDiffs.push_back(d);
            else oddDiffs.push_back(d);
        }
        sort(evenDiffs.begin(), evenDiffs.end());
        sort(oddDiffs.begin(), oddDiffs.end());
        long long total = N * N;
        long long subSum = 0, subDiff = 0;
        for(long long s: sums) subSum += cntSum(s, N);
        for(long long d: diffs) subDiff += cntDiff(d, N);
        long long intersect = 0;
        for(long long s: sums){
            long long low = max(2 - s, s - 2*N);
            long long high = min(2*N - s, s - 2);
            if(low > high) continue;
            const vector<long long> &vec = ((s&1LL)==0) ? evenDiffs : oddDiffs;
            auto itL = lower_bound(vec.begin(), vec.end(), low);
            auto itR = upper_bound(vec.begin(), vec.end(), high);
            intersect += (itR - itL);
        }
        long long freeCells = total - subSum - subDiff + intersect;
        cout<<freeCells<<"\n";
    }
    return 0;
}
